draw(interp(D,C,-0.4)--interp(D,C,1.4));
draw(interp(A,B,-0.4)--interp(A,B,1.4));
draw(A--D);
draw(B--C);

label("$y = x^2$", (3.5,3.5^2), N);
label("$y = 2x - 17$", interp(D,C,1.4), N);
[/asy]

