draw((0,-50)--(0,10));
draw(graph(parab,-10,47),red);
draw(graph(upperparab,3/2,50),blue);
draw(graph(lowerparab,3/2,50),blue);
draw(F--P--(P.x,0));
draw(P--(0,P.y));
draw(F--Q--(Q.x,0));
draw(Q--(0,Q.y));
draw((-10,10)--(50,-50),dashed);

label("$F$", F, NW, UnFill);
label("$P$", P, NE, UnFill);
label("$Q$", Q, NE, UnFill);

dot(F);
[/asy]

